(175, 576, '16.png', 3, 1, 'Chính sách giá tốt', '', '', 0, 0, 'div', '<p>G&iacute;a cả b&igrave;nh ổn, theo thị trường</p>\r\n', '', '', 527, 'vi', '1726207700'),
